package com.richemont.ce.ce_order.controller;

import com.richemont.ce.ce_order.service.ReturnService;
import com.richemont.ce_order.api.ReturnApi;
import com.richemont.ce_order.model.CreateReturnItemsRequest;
import com.richemont.ce_order.model.ResetReturnItemsRequest;
import lombok.RequiredArgsConstructor;
import lombok.extern.log4j.Log4j2;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.RestController;

@Log4j2
@RestController
@RequiredArgsConstructor
public class ReturnController implements ReturnApi {

    private final ReturnService returnService;

    @Override
    @PreAuthorize("hasAuthority('SCOPE_order:'+#tenant+':*:order-return:create')")
    public ResponseEntity<Void> createReturn(
        final String tenant,
        final CreateReturnItemsRequest createReturnRequest
    ) {
        log.info("Received request to create return for tenant: {}, request: {}", tenant, createReturnRequest);
        returnService.createReturn(tenant, createReturnRequest);
        return ResponseEntity.status(HttpStatus.CREATED).build();
    }

    @Override
    @PreAuthorize("hasAuthority('SCOPE_order:'+#tenant+':*:order-return:update')")
    public ResponseEntity<Void> resetReturnItemsByOrder(
        final String tenant,
        final ResetReturnItemsRequest resetReturnItemsRequest
    ) {
        log.info("Received request to reset return items for tenant: {}, by orderId: {}, items: {}",
                 tenant, resetReturnItemsRequest.getOrderId(), resetReturnItemsRequest.getItemIds());
        returnService.resetReturnItemsByOrder(tenant, resetReturnItemsRequest);
        return ResponseEntity.ok().build();
    }
}

