package com.richemont.ce.ce_order.controller;

import com.richemont.ce.ce_order.service.global_e.GlobalEService;
import com.richemont.ce_order.model.CheckoutCartInfo;
import jakarta.validation.Valid;
import jakarta.validation.constraints.NotNull;
import lombok.RequiredArgsConstructor;
import lombok.extern.log4j.Log4j2;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@Log4j2
@RestController
@RequiredArgsConstructor
@RequestMapping("/{tenant}/global-e")
public class GlobalEController {
    private final GlobalEService globalEService;

    @GetMapping("/checkoutCartInfo")
    @PreAuthorize("hasAuthority('SCOPE_order:'+#tenant+':*:cart:read')")
    public ResponseEntity<CheckoutCartInfo> getCheckoutCartInfo(
        @PathVariable("tenant") String tenant,
        @NotNull @Valid @RequestParam(value = "cartId") String cartId,
        @RequestParam(value = "validateStock", required = false) boolean validateStock
    ) {
        return new ResponseEntity<>(globalEService.getCartInfo(tenant, cartId, validateStock), HttpStatus.OK);
    }
}

