package com.richemont.ce.ce_order.configuration;


import jakarta.annotation.Nullable;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotEmpty;
import lombok.Data;
import lombok.Getter;
import lombok.Setter;
import lombok.extern.log4j.Log4j2;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.stereotype.Component;

import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Optional;

@Log4j2
@Getter
@Setter
@Component
@ConfigurationProperties("ce")
public class CeProperties {

    private List<String> nonOmsCountries;
    private PartnershipConfiguration partnership;

    public boolean isNonOmsMarket(String market) {
        return nonOmsCountries.contains(market);
    }

    private Map<String, String> nProdEnv;
    private List<String> returnableOrderStates;
    private List<TenantProperties> tenants;

    @NotEmpty(message = "Environment configuration is mandatory")
    @Value("${env}")
    public String env;

    public boolean isNonProd() {
        return nProdEnv.containsKey(env);
    }

    public String getEnvPrefix() {
        return nProdEnv.get(env);
    }

    public Optional<TenantProperties> getByTrigram(final String trigram) {
        return tenants.stream().filter(tenant -> tenant.getTrigram().equalsIgnoreCase(trigram)).findFirst();
    }

    @Getter
    @Setter
    public static class TenantProperties {
        @NotBlank(message = "code is mandatory")
        private String code;
        @NotBlank(message = "trigram is mandatory")
        private String trigram;
        @NotBlank(message = "name is mandatory")
        private String name;
        @Nullable
        private String orderNumberPrefix;

        @Override
        public boolean equals(Object o) {
            if (!(o instanceof TenantProperties)) {
                return false;
            }
            TenantProperties properties = (TenantProperties) o;
            return this.code.equalsIgnoreCase(properties.code);
        }

        @Override
        public int hashCode() {
            return Objects.hash(code);
        }
    }
    @Getter
    @Setter
    public static class PartnershipConfiguration {
        private List<Rule> rules;
    }

    @Data
    public static class Rule {
        private String channel;
        private String type;
        private String partnership;
    }
}

