import org.apache.commons.lang3.RandomStringUtils;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class OrderNumberGeneratorService {

    private final static int SHORT_ID_LENGTH_NPRD = 7;
    private final static int SHORT_ID_LENGTH_PRD = 8;

    private final CeProperties ceProperties;

    public String generateOrderNumber(final CeProperties.TenantConfig tenantProperties) {
        return getPrefix(tenantProperties)
                .concat(ceProperties.isNonProd() ? ceProperties.getEnvPrefix() : "")
                .concat(RandomStringUtils.randomAlphanumeric(ceProperties.isNonProd() ? SHORT_ID_LENGTH_NPRD : SHORT_ID_LENGTH_PRD).toUpperCase());
    }

    private static String getPrefix(final CeProperties.TenantConfig tenantProperties) {
        return tenantProperties.getOrderNumberPrefix() != null ? tenantProperties.getOrderNumberPrefix() : tenantProperties.getCode();
    }
}

